import mysql.connector

def import_data_with_load_data_infile(db_config, table_name, file_path, fields_terminated_by=',', lines_terminated_by='\n', ignore_lines=1):
    """
    Imports data into a MySQL table using the LOAD DATA INFILE statement.

    Args:
        db_config (dict): Dictionary containing database connection parameters
                          (e.g., 'host', 'user', 'password', 'database').
        table_name (str): The name of the table to import data into.
        file_path (str): The full path to the data file on the client machine.
        fields_terminated_by (str): The character that separates fields in the data file.
        lines_terminated_by (str): The character that separates lines in the data file.
        ignore_lines (int): The number of lines to ignore at the beginning of the file (e.g., header).
    """
    conn = None
    try:
        # Establish connection with local_infile enabled
        conn = mysql.connector.connect(
            **db_config,
            allow_local_infile=True
        )
        cursor = conn.cursor()

        # Construct the LOAD DATA INFILE statement
        # Note: The file_path must be accessible by the MySQL client (where the script runs)
        # and MySQL server must have local_infile enabled.
        load_data_sql = (
            f"LOAD DATA LOCAL INFILE '{file_path}' "
            f"INTO TABLE {table_name} "
            f"FIELDS TERMINATED BY '{fields_terminated_by}' "
            f"LINES TERMINATED BY '{lines_terminated_by}' "
            f"IGNORE {ignore_lines} LINES"
        )

        print(f"Executing: {load_data_sql}")
        cursor.execute(load_data_sql)
        conn.commit()
        print(f"Successfully imported data from '{file_path}' into table '{table_name}'.")
        print(f"{cursor.rowcount} rows imported.")

    except mysql.connector.Error as err:
        print(f"Error: {err}")
        if "local_infile" in str(err) and "is disabled" in str(err):
            print("Please ensure 'local_infile=1' is set in your MySQL server configuration (my.cnf or my.ini) and the server is restarted.")
